+int ShenandoahBarrierStubC2::available_gp_registers() {
+  return Register::available_gp_registers();
+}
+
+bool ShenandoahBarrierStubC2::is_special_register(Register r) {
+  return r == rsp || r == rbp || r == r12_heapbase || r == r15_thread;
+}
