+void ShenandoahBarrierStubC2::maybe_far_jump_if_zero(MacroAssembler& masm, Register reg) {
+  if (_narrow) {
+    __ testl(reg, reg);
+  } else {
+    __ testq(reg, reg);
+  }
+  __ jcc(Assembler::zero, *continuation());
+}
